import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c as a,o as r,ad as l}from"./chunks/mermaid.Cb40Nz1P.js";import"./chunks/cytoscape.C2CwDKBM.js";import"./chunks/dayjs.C32PoDnw.js";const k=JSON.parse('{"title":"Cowork 完整指南","description":"","frontmatter":{},"headers":[],"relativePath":"zh/products/ai-coding/claude/cowork.md","filePath":"zh/products/ai-coding/claude/cowork.md"}'),o={name:"zh/products/ai-coding/claude/cowork.md"};function n(d,t,s,i,h,c){return r(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="cowork-完整指南" tabindex="-1">Cowork 完整指南 <a class="header-anchor" href="#cowork-完整指南" aria-label="Permalink to &quot;Cowork 完整指南&quot;">​</a></h1><blockquote><p>Cowork 是 Claude Desktop 内置的<strong>桌面代理模式</strong>，让 Claude 直接读写你的本地文件、操控应用程序、执行自动化任务。它是 claude.ai 对话模式的进化——从&quot;帮你想&quot;升级为&quot;帮你做&quot;。</p></blockquote><h2 id="什么是-cowork" tabindex="-1">什么是 Cowork <a class="header-anchor" href="#什么是-cowork" aria-label="Permalink to &quot;什么是 Cowork&quot;">​</a></h2><p>Cowork 不是聊天，而是一个<strong>任务执行代理</strong>。核心区别：</p><table tabindex="0"><thead><tr><th></th><th style="text-align:center;">Claude.ai 对话模式</th><th style="text-align:center;">Cowork 代理模式</th></tr></thead><tbody><tr><td>文件访问</td><td style="text-align:center;">需手动上传</td><td style="text-align:center;">直接读写本地文件</td></tr><tr><td>任务长度</td><td style="text-align:center;">单轮对话</td><td style="text-align:center;">长时间复杂任务</td></tr><tr><td>自动化</td><td style="text-align:center;">不支持</td><td style="text-align:center;">支持定期调度</td></tr><tr><td>输出</td><td style="text-align:center;">文字/代码</td><td style="text-align:center;">Excel、PPT、文档、邮件等</td></tr><tr><td>多任务</td><td style="text-align:center;">串行对话</td><td style="text-align:center;">并行分解工作流</td></tr></tbody></table><p><strong>适用人群</strong>：Pro、Max、Team、Enterprise 付费用户，需安装 Claude Desktop（macOS / Windows）。</p><hr><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><h3 id="本地文件直接访问" tabindex="-1">本地文件直接访问 <a class="header-anchor" href="#本地文件直接访问" aria-label="Permalink to &quot;本地文件直接访问&quot;">​</a></h3><p>Claude 可以读取和写入你授权的文件夹，无需手动上传或下载。典型场景：</p><ul><li>整理 Downloads 文件夹中的文档</li><li>读取本地 CSV 并生成分析报告</li><li>批量重命名文件</li><li>读取代码目录并生成技术文档</li></ul><h3 id="专业文档生成" tabindex="-1">专业文档生成 <a class="header-anchor" href="#专业文档生成" aria-label="Permalink to &quot;专业文档生成&quot;">​</a></h3><p>Cowork 内置文档技能，可直接生成并保存到本地：</p><ul><li><strong>Excel 表格</strong>：数据分析、财务模型、甘特图</li><li><strong>PowerPoint 演示文稿</strong>：自动布局、图表嵌入</li><li><strong>Word 文档</strong>：报告、合同、说明书</li><li><strong>PDF</strong>：合并、拆分、填写表单</li></ul><h3 id="任务分解与并行" tabindex="-1">任务分解与并行 <a class="header-anchor" href="#任务分解与并行" aria-label="Permalink to &quot;任务分解与并行&quot;">​</a></h3><p>Claude 将复杂工作拆分为子任务并协调执行，例如&quot;分析上个季度所有会议记录，提取关键决策，生成摘要报告&quot;会被分解为：读取文件 → 逐个分析 → 汇总整合 → 写入输出文件。</p><h3 id="计划任务调度" tabindex="-1">计划任务调度 <a class="header-anchor" href="#计划任务调度" aria-label="Permalink to &quot;计划任务调度&quot;">​</a></h3><p>创建按频率自动运行的任务，如每日早报、每周汇总、定期文件整理。</p><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="第一步-安装并打开-claude-desktop" tabindex="-1">第一步：安装并打开 Claude Desktop <a class="header-anchor" href="#第一步-安装并打开-claude-desktop" aria-label="Permalink to &quot;第一步：安装并打开 Claude Desktop&quot;">​</a></h3><p>下载地址：</p><ul><li><a href="https://claude.ai/api/desktop/darwin/universal/dmg/latest/redirect" target="_blank" rel="noreferrer">macOS</a></li><li><a href="https://claude.ai/api/desktop/win32/x64/exe/latest/redirect" target="_blank" rel="noreferrer">Windows x64</a></li></ul><p>安装后登录你的 Claude Pro 账户。</p><h3 id="第二步-切换到-cowork-模式" tabindex="-1">第二步：切换到 Cowork 模式 <a class="header-anchor" href="#第二步-切换到-cowork-模式" aria-label="Permalink to &quot;第二步：切换到 Cowork 模式&quot;">​</a></h3><p>打开 Claude Desktop 后，在顶部标签栏切换到 <strong>Cowork</strong> 选项卡（与普通聊天标签并列）。</p><h3 id="第三步-授权文件夹" tabindex="-1">第三步：授权文件夹 <a class="header-anchor" href="#第三步-授权文件夹" aria-label="Permalink to &quot;第三步：授权文件夹&quot;">​</a></h3><p>第一次执行文件相关任务时，Cowork 会请求访问特定文件夹的权限。建议：</p><ul><li>只授权需要操作的目录（不要授权整个磁盘）</li><li>避免授权含有密码、密钥、财务凭证的目录</li></ul><h3 id="第四步-描述你的任务" tabindex="-1">第四步：描述你的任务 <a class="header-anchor" href="#第四步-描述你的任务" aria-label="Permalink to &quot;第四步：描述你的任务&quot;">​</a></h3><p>直接用自然语言描述需要完成的工作：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我读取 ~/Downloads/会议记录/ 文件夹中所有 .docx 文件，</span></span>
<span class="line"><span>提取每个文件中的&quot;行动项&quot;，汇总到一个 Excel 表格里，</span></span>
<span class="line"><span>保存为 ~/Documents/行动项汇总.xlsx</span></span></code></pre></div><p>Claude 会展示执行计划，确认后开始运行。</p><hr><h2 id="定期任务自动化" tabindex="-1">定期任务自动化 <a class="header-anchor" href="#定期任务自动化" aria-label="Permalink to &quot;定期任务自动化&quot;">​</a></h2><h3 id="⚠️-两种任务类型-关键区别" tabindex="-1">⚠️ 两种任务类型，关键区别 <a class="header-anchor" href="#⚠️-两种任务类型-关键区别" aria-label="Permalink to &quot;⚠️ 两种任务类型，关键区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th style="text-align:center;">桌面定期任务</th><th style="text-align:center;">云端定期任务</th></tr></thead><tbody><tr><td><strong>运行环境</strong></td><td style="text-align:center;">你的电脑</td><td style="text-align:center;">Anthropic 云服务器</td></tr><tr><td><strong>电脑关机能运行？</strong></td><td style="text-align:center;">❌ 必须开机</td><td style="text-align:center;">✅ 随时运行</td></tr><tr><td><strong>访问本地文件？</strong></td><td style="text-align:center;">✅ 直接访问</td><td style="text-align:center;">❌ 仅限云端</td></tr><tr><td><strong>创建入口</strong></td><td style="text-align:center;">Cowork 侧边栏</td><td style="text-align:center;">claude.ai/code 或 /schedule</td></tr><tr><td><strong>适合场景</strong></td><td style="text-align:center;">处理本地文件的任务</td><td style="text-align:center;">不依赖本地文件的任务</td></tr></tbody></table><p><strong>桌面任务</strong>：电脑必须唤醒且 Claude Desktop 保持打开。若休眠，任务跳过（不补跑）。 <strong>云端任务</strong>：运行在 Anthropic 管理的服务器上，24 小时可用，适合不需要本地文件的自动化。</p><h3 id="什么是定期任务" tabindex="-1">什么是定期任务 <a class="header-anchor" href="#什么是定期任务" aria-label="Permalink to &quot;什么是定期任务&quot;">​</a></h3><p>定期任务是保存下来的提示词 + 执行计划，可以按频率自动运行，或按需手动触发。</p><h3 id="常见使用场景" tabindex="-1">常见使用场景 <a class="header-anchor" href="#常见使用场景" aria-label="Permalink to &quot;常见使用场景&quot;">​</a></h3><ul><li><strong>每日早报</strong>：汇总过去 24 小时的邮件、日历事件，生成今日待办</li><li><strong>周报整理</strong>：每周五将本周工作日志整理成结构化报告</li><li><strong>定期研究</strong>：每天追踪特定行业新闻，生成摘要文件</li><li><strong>文件整理</strong>：每周对指定文件夹排序清理</li><li><strong>数据更新</strong>：定期拉取数据，更新 Excel 报表</li></ul><h3 id="创建方法一-用-schedule-命令" tabindex="-1">创建方法一：用 /schedule 命令 <a class="header-anchor" href="#创建方法一-用-schedule-命令" aria-label="Permalink to &quot;创建方法一：用 /schedule 命令&quot;">​</a></h3><p>在任意 Cowork 任务对话中输入 <code>/schedule</code>，Claude 会引导你完成创建：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/schedule</span></span></code></pre></div><p>Claude 会提问：任务名称、执行频率、是否绑定特定文件夹等。</p><h3 id="创建方法二-从定期任务页面" tabindex="-1">创建方法二：从定期任务页面 <a class="header-anchor" href="#创建方法二-从定期任务页面" aria-label="Permalink to &quot;创建方法二：从定期任务页面&quot;">​</a></h3><ol><li>点击左侧边栏的 <strong>定期任务</strong></li><li>点击右上角 <strong>+ 新建任务</strong></li><li>填写表单：</li></ol><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>任务名称</td><td>便于识别的名称，如&quot;每日工作早报&quot;</td></tr><tr><td>描述</td><td>简短说明任务用途</td></tr><tr><td>执行提示</td><td>Claude 每次运行时收到的完整指令</td></tr><tr><td>运行频率</td><td>每小时 / 每天 / 每周 / 工作日 / 手动</td></tr><tr><td>模型选择</td><td>默认 Claude Sonnet，复杂任务可选 Opus</td></tr><tr><td>工作文件夹</td><td>可选，绑定特定目录</td></tr></tbody></table><h3 id="管理定期任务" tabindex="-1">管理定期任务 <a class="header-anchor" href="#管理定期任务" aria-label="Permalink to &quot;管理定期任务&quot;">​</a></h3><ul><li><strong>手动触发</strong>：点击任务旁边的运行按钮，立即执行一次</li><li><strong>暂停/恢复</strong>：切换任务的启用状态</li><li><strong>查看历史</strong>：点击任务查看历次运行记录和输出</li></ul><hr><h2 id="插件系统" tabindex="-1">插件系统 <a class="header-anchor" href="#插件系统" aria-label="Permalink to &quot;插件系统&quot;">​</a></h2><h3 id="什么是插件" tabindex="-1">什么是插件 <a class="header-anchor" href="#什么是插件" aria-label="Permalink to &quot;什么是插件&quot;">​</a></h3><p>插件是将**技能（Skills）+ 连接器（Connectors）+ 子代理（Agents）**打包在一起的扩展包，安装一次即可获得一整套专项能力，无需逐个配置。</p><p>例如安装&quot;财务分析&quot;插件后，Claude 就具备了：</p><ul><li>读取财务报表的技能</li><li>连接特定财务 API 的连接器</li><li>专门处理财务分析的子代理</li></ul><h3 id="安装插件" tabindex="-1">安装插件 <a class="header-anchor" href="#安装插件" aria-label="Permalink to &quot;安装插件&quot;">​</a></h3><ol><li>打开 Claude Desktop，切换至 Cowork 选项卡</li><li>点击左侧边栏的 <strong>自定义</strong> 菜单</li><li>选择 <strong>浏览插件</strong> 查看可用选项</li><li>点击 <strong>安装</strong> 完成部署</li></ol><p>也可以上传本地自定义插件文件（<code>.skill</code> 格式）。</p><h3 id="使用插件技能" tabindex="-1">使用插件技能 <a class="header-anchor" href="#使用插件技能" aria-label="Permalink to &quot;使用插件技能&quot;">​</a></h3><p>安装插件后，在 Cowork 任务对话中：</p><ul><li>输入 <code>/</code> 查看所有可用技能列表</li><li>点击 <code>+</code> 按钮浏览并调用技能</li><li>直接描述任务，Claude 会自动匹配合适的技能</li></ul><h3 id="自定义插件" tabindex="-1">自定义插件 <a class="header-anchor" href="#自定义插件" aria-label="Permalink to &quot;自定义插件&quot;">​</a></h3><p>点击已安装插件旁边的 <strong>自定义</strong> 按钮，可以与 Claude 协作调整插件的提示词、技能和连接器配置，使其更适合你的工作流程。</p><h3 id="构建自己的插件" tabindex="-1">构建自己的插件 <a class="header-anchor" href="#构建自己的插件" aria-label="Permalink to &quot;构建自己的插件&quot;">​</a></h3><p>Cowork 内置 <strong>Plugin Creator</strong> 插件，可以指导你从零开始构建：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin-create</span></span></code></pre></div><p>按照引导完成：插件名称 → 技能定义 → 连接器配置 → 测试验证 → 导出分享。</p><hr><h2 id="claude-desktop-代码标签页-claude-code" tabindex="-1">Claude Desktop 代码标签页（Claude Code） <a class="header-anchor" href="#claude-desktop-代码标签页-claude-code" aria-label="Permalink to &quot;Claude Desktop 代码标签页（Claude Code）&quot;">​</a></h2><p>Claude Desktop 除了 Cowork 之外，还有一个<strong>代码（Code）标签页</strong>，是面向开发者的 Claude Code 图形界面，提供比终端 CLI 更多的视觉能力：</p><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td><strong>可视化 Diff 审查</strong></td><td>直观查看代码变更，支持内联注释</td></tr><tr><td><strong>App 实时预览</strong></td><td>启动开发服务器，在侧边实时预览效果</td></tr><tr><td><strong>PR 监控</strong></td><td>实时查看 CI 状态，开启 Auto-fix 让 Claude 自动修复</td></tr><tr><td><strong>并行会话</strong></td><td>多个 Claude 实例同时处理不同任务，Git worktree 自动隔离</td></tr><tr><td><strong>Dispatch</strong></td><td>从手机发送任务，桌面自动创建会话执行</td></tr><tr><td><strong>Connectors</strong></td><td>连接 GitHub、Slack、Linear 等外部服务</td></tr><tr><td><strong>SSH 会话</strong></td><td>连接远程服务器上的开发环境</td></tr><tr><td><strong>云会话</strong></td><td>启动运行在 Anthropic 云上的长期任务（电脑关机也能跑）</td></tr></tbody></table><blockquote><p>Cowork（任务代理）和 Code（编程代理）是 Claude Desktop 中的两个并列标签页，面向不同使用场景。</p></blockquote><hr><h2 id="计算机使用-computer-use" tabindex="-1">计算机使用（Computer Use） <a class="header-anchor" href="#计算机使用-computer-use" aria-label="Permalink to &quot;计算机使用（Computer Use）&quot;">​</a></h2><h3 id="什么是计算机使用" tabindex="-1">什么是计算机使用 <a class="header-anchor" href="#什么是计算机使用" aria-label="Permalink to &quot;什么是计算机使用&quot;">​</a></h3><p>Computer Use 让 Claude 能够<strong>像人一样操作你的电脑</strong>——控制鼠标、键盘、查看屏幕，从而操作任何桌面应用和浏览器，即使没有 API 接口。</p><p>典型场景：</p><ul><li>在浏览器中搜索、填写表单、提取信息</li><li>操作 Excel、Word 等桌面软件</li><li>在多个应用之间传递数据（如从邮件提取数据填入 CRM）</li></ul><h3 id="如何启用" tabindex="-1">如何启用 <a class="header-anchor" href="#如何启用" aria-label="Permalink to &quot;如何启用&quot;">​</a></h3><p>在 Claude Desktop 设置中，进入 <strong>Desktop App → Computer Use</strong> 开启。</p><p><strong>注意</strong>：启用后 Claude 在访问每个应用前会请求单独权限，你可以选择性授权。</p><h3 id="安全边界" tabindex="-1">安全边界 <a class="header-anchor" href="#安全边界" aria-label="Permalink to &quot;安全边界&quot;">​</a></h3><p>Computer Use 权限较高，建议：</p><ul><li>执行前仔细查看 Claude 的操作计划</li><li>不要在涉及网银、密码管理器等敏感应用中使用</li><li>监控任务过程，随时可以中断</li></ul><hr><h2 id="跨应用协作" tabindex="-1">跨应用协作 <a class="header-anchor" href="#跨应用协作" aria-label="Permalink to &quot;跨应用协作&quot;">​</a></h2><h3 id="从任意地方派发任务" tabindex="-1">从任意地方派发任务 <a class="header-anchor" href="#从任意地方派发任务" aria-label="Permalink to &quot;从任意地方派发任务&quot;">​</a></h3><p>Cowork 支持不打开 Claude Desktop 也能发起任务：</p><p><strong>方法</strong>：通过 Claude 的快捷方式或全局菜单，从任意应用发送任务到 Cowork 队列，Claude Desktop 会在后台接收并执行。</p><p>适用场景：在浏览器看到一篇文章想要总结并保存 → 选中文本 → 发送给 Cowork → Claude 自动处理并保存到指定文件夹。</p><h3 id="跨应用工作流示例" tabindex="-1">跨应用工作流示例 <a class="header-anchor" href="#跨应用工作流示例" aria-label="Permalink to &quot;跨应用工作流示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>场景：将本周所有电子邮件中的会议约定汇总到日历文件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude 执行步骤：</span></span>
<span class="line"><span>1. 访问邮件客户端（Computer Use）读取本周邮件</span></span>
<span class="line"><span>2. 识别包含时间、地点、参与者的会议信息</span></span>
<span class="line"><span>3. 整理成结构化数据</span></span>
<span class="line"><span>4. 写入本地日历文件或生成 .ics 文件</span></span></code></pre></div><hr><h2 id="安全使用指南" tabindex="-1">安全使用指南 <a class="header-anchor" href="#安全使用指南" aria-label="Permalink to &quot;安全使用指南&quot;">​</a></h2><p>Cowork 拥有访问你本地文件和应用的权限，请了解以下安全原则。</p><h3 id="anthropic-的保护机制" tabindex="-1">Anthropic 的保护机制 <a class="header-anchor" href="#anthropic-的保护机制" aria-label="Permalink to &quot;Anthropic 的保护机制&quot;">​</a></h3><ul><li><strong>注入攻击防护</strong>：Claude 被训练识别并拒绝恶意内容中的欺骗指令</li><li><strong>内容分类</strong>：自动扫描不受信任的内容，标记潜在风险</li><li><strong>删除保护</strong>：永久删除文件前必须获得你的明确许可</li><li><strong>按应用授权</strong>：Computer Use 访问每个应用前单独请求权限</li></ul><h3 id="你需要做的" tabindex="-1">你需要做的 <a class="header-anchor" href="#你需要做的" aria-label="Permalink to &quot;你需要做的&quot;">​</a></h3><p><strong>选择性授权</strong>：只给 Claude 访问必要文件夹的权限，避免授权含有财务信息、登录凭证的目录。</p><p><strong>监控任务</strong>：关注意外行为——Claude 访问了你没提到的文件或网站吗？</p><p><strong>谨慎设置定期任务</strong>：</p><ul><li>从简单任务开始，逐步扩展</li><li>不要自动化涉及敏感数据、不可逆操作（如发送邮件、删除文件）的任务</li><li>先手动跑几次确认结果正确，再开启自动调度</li></ul><p><strong>限制浏览器访问</strong>：网络内容是提示词注入的主要途径，将 Computer Use 的浏览器访问限制在受信任的网站。</p><p><strong>审查插件权限</strong>：安装插件前仔细阅读其权限请求，只安装来源可信的插件。</p><h3 id="你的责任边界" tabindex="-1">你的责任边界 <a class="header-anchor" href="#你的责任边界" aria-label="Permalink to &quot;你的责任边界&quot;">​</a></h3><blockquote><p>Claude 代表你执行的所有操作，由你承担最终责任，包括发布的内容、产生的交易、修改的数据。</p></blockquote><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：Cowork 任务执行时我需要一直盯着吗？</strong></p><p>不需要。你可以设置任务后离开，Claude 会在后台执行。完成后会通知你查看结果。但对于高风险操作（如批量删除、发送邮件），建议手动确认。</p><p><strong>Q：定期任务如果我的电脑关机了怎么办？</strong></p><p>任务会被跳过，下次触发时间到来时正常运行。不会&quot;补跑&quot;错过的次数（例如你出差 3 天，每日任务不会一次性跑 3 遍）。</p><p><strong>Q：Cowork 和 Claude Code 有什么区别？</strong></p><table tabindex="0"><thead><tr><th></th><th style="text-align:center;">Cowork</th><th style="text-align:center;">Claude Code</th></tr></thead><tbody><tr><td>主要用户</td><td style="text-align:center;">非开发者/通用用户</td><td style="text-align:center;">开发者</td></tr><tr><td>操作对象</td><td style="text-align:center;">文件、应用、浏览器</td><td style="text-align:center;">代码库、终端、Git</td></tr><tr><td>使用界面</td><td style="text-align:center;">Claude Desktop 图形界面</td><td style="text-align:center;">终端/IDE</td></tr><tr><td>自动化方式</td><td style="text-align:center;">定期任务</td><td style="text-align:center;">无头模式/CI</td></tr></tbody></table><p><strong>Q：插件连接器能访问防火墙后面的服务吗？</strong></p><p>标准连接器通过 Anthropic 云服务连接，自定义连接器需要指向可公开访问的服务器。内网服务需要参考网络要求文档单独配置。</p><hr><h2 id="资源" tabindex="-1">资源 <a class="header-anchor" href="#资源" aria-label="Permalink to &quot;资源&quot;">​</a></h2><ul><li><a href="https://support.claude.com/zh-CN/articles/13345190" target="_blank" rel="noreferrer">官方文档：开始使用 Cowork</a></li><li><a href="https://support.claude.com/zh-CN/articles/13364135" target="_blank" rel="noreferrer">安全使用 Cowork</a></li><li><a href="https://support.claude.com/zh-CN/articles/13837440" target="_blank" rel="noreferrer">在 Cowork 中使用插件</a></li><li><a href="https://support.claude.com/zh-CN/articles/13854387" target="_blank" rel="noreferrer">安排定期任务</a></li><li><a href="https://support.claude.com/zh-CN/articles/13892150" target="_blank" rel="noreferrer">跨应用协作</a></li></ul>`,121)])])}const C=e(o,[["render",n]]);export{k as __pageData,C as default};
